export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export type CSVRow = Record<string, any>;

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow, index: number) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, CSVRow[]>;
}

const DEFAULT_OPTIONS = {
  delimiter: ',',
  quote: '"',
  lineSeparator: '\n',
};

class CSVResultImpl implements CSVResult {
  constructor(
    public readonly rows: CSVRow[],
    public readonly headers: string[],
    public readonly errors: CSVError[]
  ) {}

  filter(predicate: (row: CSVRow, index: number) => boolean): CSVResult {
    const filteredRows = this.rows.filter(predicate);
    return new CSVResultImpl(filteredRows, this.headers, this.errors);
  }

  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      if (typeof value === 'number' && Number.isFinite(value)) {
        return acc + value;
      }
      return acc;
    }, 0);
  }

  average(column: string): number {
    let sum = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === 'number' && Number.isFinite(value)) {
        sum += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : sum / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<any, CSVRow[]> {
    const result = new Map<any, CSVRow[]>();
    for (const row of this.rows) {
      const key = row[column];
      const group = result.get(key);
      if (group) {
        group.push(row);
      } else {
        result.set(key, [row]);
      }
    }
    return result;
  }
}

function coerceValue(raw: string): any {
  if (raw === null || raw === undefined) {
    return null;
  }
  const trimmed = raw.trim();
  if (trimmed === '') {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }
  if (lower === 'true') {
    return true;
  }
  if (lower === 'false') {
    return false;
  }
  const numericPattern = /^[+-]?(?:\d+\.?\d*|\.\d+)(?:[eE][+-]?\d+)?$/;
  if (numericPattern.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num)) {
      return num;
    }
  }
  return raw;
}

function parseLine(line: string, delimiter: string, quote: string): { fields: string[]; error?: string } {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === quote) {
      if (inQuotes && line[i + 1] === quote) {
        current += quote;
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === delimiter && !inQuotes) {
      fields.push(current);
      current = '';
      continue;
    }

    current += char;
  }

  if (inQuotes) {
    fields.push(current);
    return { fields, error: 'Unclosed quoted field' };
  }

  fields.push(current);
  return { fields };
}

function cleanLine(line: string, lineSeparator: string): string {
  let cleaned = line;
  if (lineSeparator === '\n') {
    cleaned = cleaned.replace(/\r$/, '');
  }
  return cleaned;
}

function normalizeInput(input: string, lineSeparator: string): string {
  if (!input) {
    return '';
  }
  if (lineSeparator === '\n') {
    return input.replace(/\r\n/g, '\n');
  }
  return input;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? DEFAULT_OPTIONS.delimiter;
  const quote = options.quote ?? DEFAULT_OPTIONS.quote;
  const lineSeparator = options.lineSeparator ?? DEFAULT_OPTIONS.lineSeparator;

  const normalizedInput = normalizeInput(input, lineSeparator);
  if (normalizedInput === '') {
    return new CSVResultImpl([], [], []);
  }

  const rawLines = normalizedInput.split(lineSeparator);
  if (rawLines.length === 0) {
    return new CSVResultImpl([], [], []);
  }

  const cleanedLines = rawLines.map((line) => cleanLine(line, lineSeparator));
  if (cleanedLines.length === 0) {
    return new CSVResultImpl([], [], []);
  }

  if (cleanedLines[0].length === 0 && cleanedLines.length === 1) {
    return new CSVResultImpl([], [], []);
  }

  if (cleanedLines[0].length > 0 && cleanedLines[0].charCodeAt(0) === 0xfeff) {
    cleanedLines[0] = cleanedLines[0].slice(1);
  }

  const errors: CSVError[] = [];

  const headerResult = parseLine(cleanedLines[0], delimiter, quote);
  const headers = headerResult.fields;
  if (headerResult.error) {
    errors.push({ row: 1, message: headerResult.error });
  }

  const rows: CSVRow[] = [];
  for (let index = 1; index < cleanedLines.length; index++) {
    const rowLine = cleanedLines[index];
    if (rowLine === '' && headers.length === 0) {
      continue;
    }
    const rowNumber = index + 1;
    const { fields, error } = parseLine(rowLine, delimiter, quote);
    if (error) {
      errors.push({ row: rowNumber, message: error });
    }

    if (headers.length === 0) {
      rows.push({});
      continue;
    }

    if (fields.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} column(s) but found ${fields.length}`,
      });
    }

    const row: CSVRow = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex++) {
      const header = headers[columnIndex];
      const value = fields[columnIndex] ?? '';
      row[header] = coerceValue(value);
    }
    rows.push(row);
  }

  return new CSVResultImpl(rows, headers, errors);
}
