function assertDeepEqual(actual: any, expected: any, message: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}\nExpected: ${expectedJson}\nReceived: ${actualJson}`);
  }
}

function testBasicParsing() {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Basic parsing should return two rows');
  assertDeepEqual(result.headers, ['name', 'age'], 'Headers should match');
  assertDeepEqual(result.rows[0], { name: 'Alice', age: 30 }, 'First row should match');
  assertDeepEqual(result.rows[1], { name: 'Bob', age: 25 }, 'Second row should match');
  assert(result.errors.length === 0, 'There should be no errors for well-formed input');
}

function testQuotedFields() {
  const csv = 'name,notes\nAlice,"Hello, world"\nBob,"One, two, three"';
  const result = parseCSV(csv);
  assertDeepEqual(result.rows[0].notes, 'Hello, world', 'Quoted fields should retain commas');
  assertDeepEqual(result.rows[1].notes, 'One, two, three', 'Quoted fields with multiple commas should work');
}

function testEscapedQuotes() {
  const csv = 'quote\n"She said ""Hello"""';
  const result = parseCSV(csv);
  assertDeepEqual(result.rows[0].quote, 'She said "Hello"', 'Escaped quotes should produce literal quotes');
}

function testCustomDelimiterAndLineSeparator() {
  const csv = 'name|value<>A|1<>B|2';
  const result = parseCSV(csv, { delimiter: '|', lineSeparator: '<>' });
  assertDeepEqual(result.headers, ['name', 'value'], 'Custom delimiter should parse headers');
  assert(result.rows.length === 2, 'Custom line separator should yield two rows');
  assertDeepEqual(result.rows[0], { name: 'A', value: 1 }, 'Numeric coercion with custom delimiter');
  assertDeepEqual(result.rows[1], { name: 'B', value: 2 }, 'Second row should parse correctly');
}

function testTypeCoercion() {
  const csv = 'num,float,bool,nullish,empty,text\n1,2.5, TRUE ,null,, hello ';
  const result = parseCSV(csv);
  const row = result.rows[0];
  assert(row.num === 1, 'Integers should become numbers');
  assert(row.float === 2.5, 'Floats should become numbers');
  assert(row.bool === true, 'Boolean should be normalized');
  assert(row.nullish === null, 'null values should convert to null');
  assert(row.empty === null, 'Empty cells should become null');
  assert(row.text === ' hello ', 'Non-matching text should remain as string');
}

function testMalformedRows() {
  const csv = 'name,age\nAlice,30\nBob';
  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Malformed row should still yield an object');
  assert(result.rows[1].age === null, 'Missing column should default to null');
  assert(result.errors.length >= 1, 'Missing column should produce an error');
  assert(
    result.errors.some((error) => error.message.includes('Expected 2 column(s) but found 1')),
    'Error should mention mismatched column count'
  );

  const broken = 'name,quote\nAlice,"Unfinished text';
  const brokenResult = parseCSV(broken);
  assert(
    brokenResult.errors.some((error) => error.message === 'Unclosed quoted field'),
    'Unclosed quotes should be reported as an error'
  );
}

function testFilteringAndAggregations() {
  const csv = 'category,value\nA,10\nB,5\nA,15\nC,invalid';
  const result = parseCSV(csv);
  assert(result.sum('value') === 30, 'Sum should only include numeric values');
  assert(result.average('value') === 10, 'Average should divide by numeric count');
  assert(result.count() === 4, 'Count should include all rows');
  const grouped = result.groupBy('category');
  assert(grouped.get('A')?.length === 2, 'Group A should contain two rows');
  assert(grouped.get('B')?.[0].value === 5, 'Group B should contain the correct row');
  assert(grouped.get('C')?.[0].value === 'invalid', 'Non-numeric group value should stay string');

  const filtered = result.filter((row) => row.category === 'A');
  assert(filtered.rows.length === 2, 'Filter should reduce rows');
  assert(filtered.sum('value') === 25, 'Filtered sum should reflect filtered rows');
  assert(filtered.count() === 2, 'Filtered count should match filtered rows');
  assert(filtered.headers.length === result.headers.length, 'Headers should remain intact after filtering');
