  const largeField = 'x'.repeat(5000);
  const largeCSV = `text\n"${largeField}"`;
  const largeResult = parseCSV(largeCSV);
  assert(largeResult.rows[0].text === largeField, 'Large fields should be preserved');
}

function runTests() {
  console.log('Running CSV parser tests...');
  testBasicParsing();
  testQuotedFields();
  testEscapedQuotes();
  testCustomDelimiterAndLineSeparator();
  testTypeCoercion();
  testMalformedRows();
  testFilteringAndAggregations();
  testEdgeCases();
